/**
 * polyglot-betti-bridge.test.ts
 *
 * Unit tests for the JS-side builder helpers and the Rust WASM compiler.
 *
 * Builder helper tests run without WASM.
 * WASM round-trip tests skip gracefully if pkg/ hasn't been built.
 */
import { describe, it, expect, beforeAll } from 'vitest';
import {
  buildPolyglotFnInput,
  callArg,
  callStmt,
  id,
  lit,
  member,
  parallel,
  ret,
  varDecl,
} from './polyglot-betti-bridge';

// ── Pure builder-helper tests (no WASM required) ──────────────────────────

describe('PolyglotFnInput builder helpers', () => {
  it('roundtrips a simple Python function JSON correctly', () => {
    const input = buildPolyglotFnInput(
      'python',
      'process_data',
      ['data'],
      [
        varDecl(['result'], { kind: 'call', callee: id('transform'), args: [id('data')] }),
        ret(id('result')),
      ],
      'process.py',
    );

    expect(input.language).toBe('python');
    expect(input.name).toBe('process_data');
    expect(input.params).toEqual(['data']);
    expect(input.file_path).toBe('process.py');
    expect(input.body).toHaveLength(2);

    const declStmt = input.body[0];
    expect(declStmt.kind).toBe('var_decl');
    if (declStmt.kind === 'var_decl') {
      expect(declStmt.bindings).toEqual(['result']);
      expect(declStmt.init?.kind).toBe('call');
    }

    const retStmt = input.body[1];
    expect(retStmt.kind).toBe('return');
    if (retStmt.kind === 'return') {
      expect(retStmt.value?.kind).toBe('identifier');
    }
  });

  it('builds a parallel fan-out (Go-style goroutines)', () => {
    const input = buildPolyglotFnInput(
      'go',
      'FetchMultiple',
      ['ctx'],
      [
        parallel(['resA', 'resB'], [
          { callee: id('fetchA'), args: [id('ctx')], assign_to: 'resA' },
          { callee: id('fetchB'), args: [id('ctx')], assign_to: 'resB' },
        ]),
        ret(id('resA')),
      ],
    );

    expect(input.body[0].kind).toBe('parallel');
    if (input.body[0].kind === 'parallel') {
      expect(input.body[0].branches).toHaveLength(2);
    }
  });

  it('builds a member access call (Python self.method)', () => {
    const input = buildPolyglotFnInput(
      'python',
      'save',
      ['self'],
      [
        callStmt(member(id('self'), 'persist'), [lit(true)]),
        ret(),
      ],
    );

    const callNode = input.body[0];
    expect(callNode.kind).toBe('call');
    if (callNode.kind === 'call') {
      expect(callNode.callee.kind).toBe('member');
    }
  });

  it('serialises cleanly to JSON (no undefined fields)', () => {
    const input = buildPolyglotFnInput('rust', 'run', ['args'], [ret(lit(0))]);
    const json = JSON.stringify(input);
    const parsed = JSON.parse(json);
    expect(parsed.language).toBe('rust');
    expect(parsed.body[0].kind).toBe('return');
  });

  it('generates correct var_decl for simple assignment', () => {
    const input = buildPolyglotFnInput(
      'typescript',
      'double',
      ['x'],
      [
        varDecl(['y'], id('x')),
        ret(id('y')),
      ],
    );
    const decl = input.body[0];
    expect(decl.kind).toBe('var_decl');
    if (decl.kind === 'var_decl') {
      expect(decl.init?.kind).toBe('identifier');
    }
  });

  it('retains ghostMass payload inside serialization', () => {
    const input = buildPolyglotFnInput(
      'rust',
      'ghost_fn',
      ['x'],
      [
        varDecl(['y'], lit(42, { raw: '42' }), { source: 'let y = 42;' }),
        ret(id('y', { origin: 'local' }), { trailing_comment: '// return it' }),
      ],
    );
    const json = JSON.stringify(input);
    const parsed = JSON.parse(json);
    expect(parsed.body[0].ghost_mass).toEqual({ source: 'let y = 42;' });
    expect(parsed.body[0].init.ghost_mass).toEqual({ raw: '42' });
    expect(parsed.body[1].ghost_mass).toEqual({ trailing_comment: '// return it' });
    expect(parsed.body[1].value.ghost_mass).toEqual({ origin: 'local' });
  });
});

// ── WASM round-trip tests ─────────────────────────────────────────────────
// Skipped gracefully if WASM pkg/ hasn't been built.

describe('compile_polyglot_fn WASM round-trip', () => {
  let compilePolyglotFn = null;

  beforeAll(async () => {
    try {
      const mod = await import('./polyglot-betti-bridge.js');
      const pkgPath = require.resolve(
        '../../gnosis-betti-wasm/pkg/gnosis_betti_wasm.js',
      ).replace(/\\/g, '/');
      await mod.initPolyglotBettiWasm('file://' + pkgPath);
      compilePolyglotFn = mod.compilePolyglotFn;
    } catch {
      // WASM not built or unavailable in this test environment — skip.
      compilePolyglotFn = null;
    }
  });

  it.each([
    ['python', 'process_data', ['data'],
      [varDecl(['r'], { kind: 'call', callee: id('transform'), args: [id('data')] }), ret(id('r'))],
    ],
    ['rust', 'compute', ['n'],
      [varDecl(['sq'], { kind: 'call', callee: id('mul'), args: [id('n'), id('n')] }), ret(id('sq'))],
    ],
    ['go', 'compute_ghost', ['n'],
      [varDecl(['sq'], callArg(id('mul'), [id('n'), id('n')], { span: [1, 10] }), { source: 'sq := mul(n, n)' }), ret(id('sq'))],
    ],
    ['lean', 'theorem_proof', [], [ret()]],
  ])('compiles %s function to topology', (lang, name, params, body) => {
    if (!compilePolyglotFn) {
      return; // skip — WASM not available
    }
    const input = buildPolyglotFnInput(lang, name, params, body);
    const result = compilePolyglotFn(input);
    expect(result.functionName).toBe(name);
    expect(result.language).toBe(lang);
    expect(result.topologySource.length).toBeGreaterThan(0);
    expect(result.schedule.length).toBeGreaterThan(0);
    expect(result.transpiledSources).toBeDefined();
    expect(result.transpiledSources.python).toBeDefined();
    expect(result.transpiledSources.rust).toBeDefined();
    expect(result.transpiledSources.go).toBeDefined();
  });

  it('proves native transpilation formatting and ghost_mass generic emission', () => {
    if (!compilePolyglotFn) return;

    const input = buildPolyglotFnInput(
      'ruby',
      'fetch_data',
      ['id'],
      [
        varDecl(
          ['response'], 
          callArg(member(id('HTTP'), 'get'), [id('id')]), 
          { source: 'response = HTTP.get(id)' }
        ),
        ret(id('response'), { source: 'return response' }),
      ]
    );

    const result = compilePolyglotFn(input);

    // 1. Prove Ruby returns EXACT ghost mass strings because target == source (GenericEmitter match)
    expect(result.transpiledSources.ruby).toContain('response = HTTP.get(id)\n');
    expect(result.transpiledSources.ruby).toContain('return response\n');

    // 2. Prove Python transpile translates to its specific syntax
    expect(result.transpiledSources.python).toContain('response = await HTTP.get(id)');
    expect(result.transpiledSources.python).toContain('return response');

    // 3. Prove Rust transpile translates to its specific syntax
    expect(result.transpiledSources.rust).toContain('let response = HTTP.get(id).await;');
    expect(result.transpiledSources.rust).toContain('return response;');

    // 4. Prove Go transpile translates to its specific syntax
    expect(result.transpiledSources.go).toContain('response := HTTP.get(id)');
    expect(result.transpiledSources.go).toContain('return response');
    
    // 5. Prove an unsupported target language (e.g. cpp) shows the unsupported comment
    expect(result.transpiledSources.cpp).toContain('// Transpilation to cpp is not yet natively supported in Babelfish Phase 2.');
  });

  const allSupportedLanguages = [
    'c', 'cpp', 'csharp', 'elixir', 'fsharp', 'go', 'haskell',
    'java', 'javascript', 'kotlin', 'lean', 'lua', 'ocaml',
    'php', 'python', 'ruby', 'rust', 'scala', 'swift', 'typescript', 'zig'
  ];

  it.each(allSupportedLanguages)('proves exact ghost_mass transpilation natively binds for source language: %s', (lang) => {
    if (!compilePolyglotFn) return;

    const input = buildPolyglotFnInput(
      lang,
      'polyglot_fetch',
      ['id'],
      [
        varDecl(
          ['response'], 
          callArg(member(id('HTTP'), 'get'), [id('id')]), 
          { source: `val response = ${lang}.get(id)` }
        ),
        ret(id('response'), { source: `return ${lang}Response` }),
      ]
    );

    const result = compilePolyglotFn(input);
    
    // Every language when matching its own input source language should natively use 
    // the ghost mass bypass regardless of whether it's Python, Rust, Go or Generic.
    expect(result.transpiledSources[lang]).toContain(`val response = ${lang}.get(id)\n`);
    expect(result.transpiledSources[lang]).toContain(`return ${lang}Response\n`);
    
    // For a mismatched language without a structural generator (e.g. ocaml when lang is c), it should emit the placeholder
    const otherLang = lang === 'ocaml' ? 'haskell' : 'ocaml';
    expect(result.transpiledSources[otherLang]).toContain(`// Transpilation to ${otherLang} is not yet natively supported in Babelfish Phase 2.`);
  });
});
